function getUser(id) {
  return fetch(`/api/users/${id}`).json();
  // 网络失败 → Uncaught TypeError → 页面白屏
  // 用户看到："Something went wrong"
}

async function getUser(id) {
  try {
    const res = await fetch(`/api/users/${id}`);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return await res.json();
  } catch (err) {
    console.error('加载用户失败:', err);
    return null;  // 兜底，调用方判断 null
  }
}

try {
  // ① 尝试执行可能出错的操作
  const data = JSON.parse(input);
  processData(data);
} catch (err) {
  // ② 捕获错误（仅同步错误）
  console.error(err.message);
  rollbackChanges();
} finally {
  // ③ 无论成功失败都执行（清理资源）
  closeConnection();
  hideLoading();
}

try {
  riskyOperation();
} catch (err) {
  if (err instanceof TypeError) {
    console.log('类型错误，检查参数');
  } else if (err instanceof RangeError) {
    console.log('范围错误，检查边界');
  } else {
    console.log('未知错误:', err.message);
  }
}

sections.text:
业务错误用自定义类继承 Error，方便统一捕获和处理：

class ValidationError extends Error {
  constructor(field, msg) {
    super(msg);
    this.name = 'ValidationError';
    this.field = field;
  }
}

sections.code:
try {
  fetch('/api/data');  // 返回 Promise，未 await
  // Promise reject 时，try/catch 捕获不到
} catch (err) {
  console.log('永远进不来这里');
}

// 正确做法：用 .catch() 或 await + try/catch

async function loadData() {
  try {
    const res = await fetch('/api/data');
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return await res.json();
  } catch (err) {
    console.error('加载失败:', err.message);
    return null;  // 兜底返回
  }
}

sections.text:
.catch() 适合"失败给默认值"的简洁写法：

const data = await fetch(url).then(r => r.json()).catch(() => []);

try/catch 适合复杂错误处理逻辑，可读性更好。

sections.code:
function validateEmail(email) {
  if (!email.includes('@')) {
    throw new ValidationError('email', '邮箱格式错误');
  }
  return email;
}

// 调用方捕获
try { validateEmail(input); }
catch (err) { showFieldError(err.field, err.message); }

// Node.js
process.on('uncaughtException', (err) => {
  logger.error('未捕获异常:', err);
  process.exit(1);
});
process.on('unhandledRejection', (reason) => {
  logger.error('未处理的 Promise 拒绝:', reason);
});

// 浏览器
window.addEventListener('unhandledrejection', (e) => {
  console.error('未处理的 Promise:', e.reason);
});

