  debugger;  // 代码执行到这里会暂停
  // 打开 DevTools → Sources → 找到这行
  // 可以查看变量、调用栈、作用域
  return process(data);
}

// 同步错误
try { riskyOp(); } catch (e) { ... } finally { cleanup(); }

// 异步错误
try { await p; } catch (e) { ... }
await p.catch(e => null);

// 自定义错误
class BizError extends Error { code: string; }

// 全局兜底
